<script setup lang="ts">
import { ref, onMounted } from 'vue';

const longUrl = ref('');
const history = ref<{ original: string; short: string }[]>([]);

// Load history from local storage on mount
onMounted(() => {
  const savedHistory = localStorage.getItem('vue-shorten-history');
  if (savedHistory) {
    try {
      history.value = JSON.parse(savedHistory);
    } catch (e) {
      console.error('Failed to parse history from local storage');
    }
  }
});

const shortenUrl = () => {
  if (!longUrl.value || !longUrl.value.trim()) return;

  // Simulating Bitly API shortening for functional demo
  // Real implementation would involve an async fetch call to Bitly v4 API
  const simulatedShort = `https://bit.ly/${Math.random().toString(36).substring(7)}`;

  const newEntry = {
    original: longUrl.value,
    short: simulatedShort
  };

  history.value.unshift(newEntry);
  localStorage.setItem('vue-shorten-history', JSON.stringify(history.value));
  longUrl.value = '';
};

const clearHistory = () => {
  history.value = [];
  localStorage.removeItem('vue-shorten-history');
};
</script>

